VALUES
  ('social-worker-moex-02686', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依2008年由社會工作師全國聯合會所訂定的社會工作師倫理守則，其中有關社會工作師做為專業人員的 倫理責任共四條，下列敘述何者不在其中？', '["社會工作師應不斷進修努力，提升社會工作專業知能以服務案主及推展社會福利服務", "社會工作師應包容多元文化尊重多元社會現象，防止因種族、宗教、性別、國籍、年齡、婚姻狀態及 身心障礙、宗教信仰及政治理念等歧視，所造成的社會不公平現象", "社會工作師嚴禁參與違法之活動，並注意自我言行對案主、服務機構、社會大眾所產生影響", "社會工作師得加入社會工作師公會，共同推動社會工作專業發展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02687', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區培力（充權）的敘述，下列何者錯誤？', '["屬於一個連續的過程", "可經由對話而覺察", "重視反思，對於行動則較保留，以避免衝突", "是一種提供反壓迫的綜合性方法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02688', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某公部門承辦人員：「申請計畫需在很快的時間內提出，社區沒辦法做得到，有的還沒意願，我就把申 請衛生福利部補助計畫給他們看一下，找一項來寫，跟他們開個會，研訂怎麼寫，趕快寫…」，請問上 述情境，是依據何項需求屬性擬訂計畫？', '["感受性需求", "表達性需求", "規範性需求", "實證性需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02689', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作模式中的地區發展（locality development）模式認為其最主要的改變技術是：', '["調查社區需求", "直接行動", "理性規劃解決問題", "形成社區共識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02690', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '將社區的資源去除重疊、填補空隙，以投入特定任務，朝向同一共識目標的實務技術是指：', '["資源調查", "資源開發", "資源動員", "資源整合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02691', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區意識是社區工作要素之一，其包括熟悉感、認同感、歸屬感與榮譽感四項構念，下列敘述何者錯 誤？', '["熟悉感是此四構念的重要基礎", "有認同感必可轉化為社區行動", "榮譽感有賴於來自社區外部的肯定", "社區報或通訊可增加熟悉感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02692', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作的目標包括任務目標與過程目標，若社區工作者想要同時達到時，下列何者不是社區工作的要 素？', '["注意社區的步調", "激發社區改變的意願", "社區工作的計劃係由專業者決定", "引導社區參與計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02693', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者是社區工作者協助社區解決問題正確的步驟？', '["協助建立社區組織→協助研究社區→協助規劃社區方案→協助執行社區方案→協助評估社區工作", "協助研究社區→協助建立社區組織→協助規劃社區方案→協助執行社區方案→協助評估社區工作", "協助規劃社區方案→協助建立社區組織→協助研究社區→協助執行社區方案→協助評估社區工作", "協助研究社區→協助評估社區工作→協助規劃社區方案→協助執行社區方案→協助建立社區組織"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02694', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '由宏觀的角度觀察，目前臺灣社區發展的重要問題是：', '["社區範圍的劃定係由社區民眾自主決策", "官方主導性弱", "對公部門資源依賴太深", "社區發展的工作項目完全由協會自訂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02695', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作主要可區分為社區發展、社區／社會計劃和社會行動三種模式，下列有關三種模式的工作者角 色之敘述何者正確？', '["社區發展模式是倡導者", "社區／社會計劃模式是專家", "社會行動模式是使能者", "社區發展模式是行動者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02696', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區睦鄰中心發祥於英國，而有關當時英國社區睦鄰中心的作法，下列敘述何者錯誤？', '["設於貧民區，備有宿舍，所有工作人員必須住在中心內", "盡量發動當地人力，培養當地人民自動自發，互助合作，為地方服務", "使社區中心成為當地之服務中心和文化中心", "有既定的工作計畫，辦理各種類服務工作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02697', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作會採用社區工作方法協助社區解決問題主要是基於下列那一項工作假設？', '["社區中的人們無能發展出處理社區問題的能力", "人們希望改變，但無能改變", "社區民眾需要被協助進行組織，以解決社區的問題", "主要以「片段方式」即能成功解決社區的問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02698', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區評估的敘述，下列何者錯誤？', '["評估社區整備程度時須針對特定議題", "代價是可行性評估中的重要指標", "探討社區資源的可近性是屬於社區參與的評估", "評估初期對社區問題的請求與宣稱，會暫時以「資訊」的性質來看待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02699', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '自1982年英國The Barclay Report出爐後，社區工作與社區照顧扯上關係。之後英國又在1990年通過 「健康服務暨社區照顧法案」，於是社區照顧成了國家福利的另一選擇，而下列何者非社區照顧的內涵？', '["長期照護", "去機構化", "減少公共依賴", "無需成本考量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02700', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據全美社會工作專業人員協會規定，下列何者不是社會工作專業的價值？', '["承諾個人對社會的重要性", "願意散播相關的知識與技巧", "承諾追求人類最大的福祉", "承諾改變個人以滿足社會的需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02701', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在任務性團體中所使用的腦力激盪方法的敘述，下列何者錯誤？', '["是一種自我激勵與享受的過程", "可在短時間內產出大量的意見", "適用在需要有系統有組織思考的團體過程中", "在較大團體中，選擇異質性較高的成員發言，亦可進行腦力激盪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02702', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體領導者如何在團體中發展出對文化的敏感度，下列何者錯誤？', '["誠實探討自己對成員所產生的偏見或刻板的假設", "避免在團體中探討認同差異的問題，以維持團體凝聚力", "透過社會圖像的製作，了解成員正式與非正式的社會關係", "了解社會態度會對不同文化的成員產生那些影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02703', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體契約在不同團體發展階段的敘述，下列何者正確？', '["互惠契約是指成員去反省先前訂的契約之可行性，是否需要進行修正，通常發生在團體衝突階段", "互助契約的特徵是抽象與外推，以高層次的方式呈現如何達成團體目標，通常發生在團體初期", "互賴契約是指在團體維持期的社會工作者，有責任向成員提出應保持在團體開始時的目標之一致性", "獨立契約是將個人契約新增了團體經驗，通常發生在團體形成期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02704', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在團體中，某位女性成員談到她同時與幾位男孩子來往，約會很多，卻一直無法確定那一個人才是自己 的終身伴侶，一時之間，許多成員瞪著該女性成員直看，而該女性成員也發現自己沒有得到正向反應而 臉紅羞愧。此時，領導者為解除場面僵局，向成員們表示，如果未達論及婚嫁，擁有兩位以上異性朋友 的現象應該也有不少人有類似情況。請問，該名領導者使用的技巧是：', '["示範", "認知重建", "面質", "普遍化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02705', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體中代罪羔羊（scapegoat）的敘述，下列何者錯誤？', '["其可能是個人，也可能是團體中的次團體", "在獨裁的團體裡，代罪羔羊的出現是意味團體成員有想爭取高社會地位的渴望", "代罪羔羊可以用來做為團體目標遲遲不能達成的藉口", "代罪羔羊的形成都是人格的問題，例如：缺乏控制他人動機、缺乏適應性學習能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02706', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有一項可促成個人改變的團體治療因素，是引導團體成員把自己的感受、思考、資訊、物資分享給其他 成員，特別是一些隱藏已久，或不易攤開來的部分，請問這項因素是指：', '["領悟", "自我揭露", "代償學習", "利他主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02707', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會團體工作的組成與運作有著既定的目標，其目標之敘述何者正確？', '["機構目標係指每一個團體成員的願望就是促使成員願意維持團體成員身分的動力", "團體目標通常是與需求有關，所以當機構推行新服務時，通常會向社會大眾說明", "團體成員目標是融合機構與團體成員目標，讓團體成員發揮良好社會功能", "團體工作者目標係指工作者運用計畫、方法、工具和方案，幫助成員達到其目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02708', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主：「我一直心情很不好，常感到日子不好過。」社會工作者：「你可以說明一下你過怎樣的日子？」 以上的對話是會談過程的那一種表達技術？', '["簡述語意的技術", "尊重接納的技術", "具體的技術", "情緒反映的技術"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02709', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作對團體的界定重視實施的運作，所以不同目標的團體有其人數的偏好。下列有關決定團體規模 的原則何者錯誤？', '["團體大到使成員均能得到刺激，小到足夠參與個人認知", "團體以小到能產生工作效果，大到能被社會工作者掌握", "團體要以能圍坐而相互看得到對方或聽得到對方的聲音", "開放性團體可以不太重視團體成員的多寡，但封閉性團體的大小卻很重要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02710', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據社會團體工作主要三個工作模型的分析，下列敘述何者錯誤？', '["社會目標模型強調團體過程的民主性，是屬於過程模型", "治療模型是臨床與個別取向，是屬於目標模型", "交互模型是中介協調與團體導向，是屬於過程模型", "治療模型與交互模型都是屬於治療取向的模型"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
